"""
Launch Interceptor Program — DECIDE (Knight & Leveson, 1986).
Single module: `decide` and `realcompare`.
"""

from __future__ import annotations

import math
from typing import Any, Dict, List, Optional, Tuple

PI = 3.1415926535


def realcompare(a: float, b: float) -> str:
    """
    Compare two reals using six significant digits (per spec).
    Returns "LT", "EQ", or "GT".
    """
    ra = _round_to_sig_figs(a, 6)
    rb = _round_to_sig_figs(b, 6)
    if ra < rb:
        return "LT"
    if ra > rb:
        return "GT"
    return "EQ"


def _round_to_sig_figs(x: float, sig_figs: int) -> float:
    if x == 0.0:
        return 0.0
    ax = abs(x)
    exp = math.floor(math.log10(ax))
    scale = 10.0 ** (sig_figs - 1 - exp)
    rounded = round(ax * scale) / scale
    return math.copysign(rounded, x)


def _dist_sq(x: List[float], y: List[float], i: int, j: int) -> float:
    dx = x[j] - x[i]
    dy = y[j] - y[i]
    return dx * dx + dy * dy


def _dist(x: List[float], y: List[float], i: int, j: int) -> float:
    return math.sqrt(_dist_sq(x, y, i, j))


def _triangle_area_twice(ax: float, ay: float, bx: float, by: float, cx: float, cy: float) -> float:
    return (bx - ax) * (cy - ay) - (by - ay) * (cx - ax)


def _min_circle_radius_three(
    ax: float, ay: float, bx: float, by: float, cx: float, cy: float
) -> float:
    """Minimum radius of a circle that contains all three points (2D)."""
    cp2 = _triangle_area_twice(ax, ay, bx, by, cx, cy)
    a2 = (bx - cx) ** 2 + (by - cy) ** 2  # squared length BC (opposite vertex A)
    b2 = (ax - cx) ** 2 + (ay - cy) ** 2  # squared length AC (opposite vertex B)
    c2 = (ax - bx) ** 2 + (ay - by) ** 2  # squared length AB (opposite vertex C)

    if realcompare(cp2, 0.0) == "EQ":
        d1 = math.sqrt(c2)
        d2 = math.sqrt(a2)
        d3 = math.sqrt(b2)
        m = d1
        if realcompare(d2, m) == "GT":
            m = d2
        if realcompare(d3, m) == "GT":
            m = d3
        return m / 2.0

    # Obtuse at A iff a² > b² + c² (with standard vertex naming A,B,C)
    if realcompare(a2, b2 + c2) == "GT":
        return math.sqrt(a2) / 2.0
    if realcompare(b2, a2 + c2) == "GT":
        return math.sqrt(b2) / 2.0
    if realcompare(c2, a2 + b2) == "GT":
        return math.sqrt(c2) / 2.0

    a = math.sqrt(a2)
    b = math.sqrt(b2)
    c = math.sqrt(c2)
    area = abs(cp2) / 2.0
    return (a * b * c) / (4.0 * area)


def _quadrant(px: float, py: float) -> int:
    if realcompare(px, 0.0) == "EQ" and realcompare(py, 0.0) == "EQ":
        return 1
    if realcompare(px, 0.0) == "EQ":
        return 1 if realcompare(py, 0.0) == "GT" else 3
    if realcompare(py, 0.0) == "EQ":
        return 1 if realcompare(px, 0.0) == "GT" else 2
    if realcompare(px, 0.0) == "GT" and realcompare(py, 0.0) == "GT":
        return 1
    if realcompare(px, 0.0) == "LT" and realcompare(py, 0.0) == "GT":
        return 2
    if realcompare(px, 0.0) == "LT" and realcompare(py, 0.0) == "LT":
        return 3
    return 4


def _point_line_distance(
    x: List[float], y: List[float], i0: int, imid: int, i1: int
) -> float:
    x0, y0 = x[i0], y[i0]
    x1, y1 = x[i1], y[i1]
    xm, ym = x[imid], y[imid]
    if realcompare(x0, x1) == "EQ" and realcompare(y0, y1) == "EQ":
        return _dist(x, y, imid, i0)
    dx = x1 - x0
    dy = y1 - y0
    t_num = (xm - x0) * dx + (ym - y0) * dy
    t_den = dx * dx + dy * dy
    if realcompare(t_den, 0.0) == "EQ":
        return _dist(x, y, imid, i0)
    t = t_num / t_den
    px = x0 + t * dx
    py = y0 + t * dy
    return math.sqrt((xm - px) ** 2 + (ym - py) ** 2)


def _angle_at_vertex(
    x1: float, y1: float, vx: float, vy: float, x3: float, y3: float
) -> Optional[float]:
    if (realcompare(x1, vx) == "EQ" and realcompare(y1, vy) == "EQ") or (
        realcompare(x3, vx) == "EQ" and realcompare(y3, vy) == "EQ"
    ):
        return None
    v1x, v1y = x1 - vx, y1 - vy
    v2x, v2y = x3 - vx, y3 - vy
    n1 = math.sqrt(v1x * v1x + v1y * v1y)
    n2 = math.sqrt(v2x * v2x + v2y * v2y)
    if realcompare(n1, 0.0) == "EQ" or realcompare(n2, 0.0) == "EQ":
        return None
    c = (v1x * v2x + v1y * v2y) / (n1 * n2)
    if realcompare(c, 1.0) == "GT":
        c = 1.0
    if realcompare(c, -1.0) == "LT":
        c = -1.0
    return math.acos(c)


def _lic1(x: List[float], y: List[float], n: int, length1: float) -> bool:
    for i in range(n - 1):
        d = _dist(x, y, i, i + 1)
        if realcompare(d, length1) == "GT":
            return True
    return False


def _lic2(x: List[float], y: List[float], n: int, radius1: float) -> bool:
    for i in range(n - 2):
        r = _min_circle_radius_three(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic3(x: List[float], y: List[float], n: int, epsilon: float) -> bool:
    for i in range(n - 2):
        ang = _angle_at_vertex(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        if ang is None:
            continue
        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
    return False


def _lic4(x: List[float], y: List[float], n: int, area1: float) -> bool:
    for i in range(n - 2):
        t = _triangle_area_twice(x[i], y[i], x[i + 1], y[i + 1], x[i + 2], y[i + 2])
        area = abs(t) / 2.0
        if realcompare(area, area1) == "GT":
            return True
    return False


def _lic5(x: List[float], y: List[float], n: int, q_pts: int, quads: int) -> bool:
    for start in range(n - q_pts + 1):
        seen = set()
        for k in range(q_pts):
            idx = start + k
            seen.add(_quadrant(x[idx], y[idx]))
        if len(seen) > quads:
            return True
    return False


def _lic6(x: List[float], y: List[float], n: int) -> bool:
    for i in range(n - 1):
        j = i + 1
        if realcompare(x[j] - x[i], 0.0) == "LT":
            return True
    return False


def _lic7(x: List[float], y: List[float], n: int, n_pts: int, dist_param: float) -> bool:
    if realcompare(float(n), 3.0) == "LT":
        return False
    for start in range(n - n_pts + 1):
        i0 = start
        i1 = start + n_pts - 1
        if realcompare(x[i0], x[i1]) == "EQ" and realcompare(y[i0], y[i1]) == "EQ":
            for k in range(1, n_pts - 1):
                im = start + k
                d = _dist(x, y, im, i0)
                if realcompare(d, dist_param) == "GT":
                    return True
        else:
            for k in range(1, n_pts - 1):
                im = start + k
                d = _point_line_distance(x, y, i0, im, i1)
                if realcompare(d, dist_param) == "GT":
                    return True
    return False


def _lic8(x: List[float], y: List[float], n: int, k_pts: int, length1: float) -> bool:
    if realcompare(float(n), 3.0) == "LT":
        return False
    span = k_pts + 1
    for i in range(n - span):
        j = i + span
        d = _dist(x, y, i, j)
        if realcompare(d, length1) == "GT":
            return True
    return False


def _lic9(x: List[float], y: List[float], n: int, a_pts: int, b_pts: int, radius1: float) -> bool:
    if realcompare(float(n), 5.0) == "LT":
        return False
    span = a_pts + b_pts + 2
    for i in range(n - span + 1):
        j = i + a_pts + 1
        k = i + a_pts + b_pts + 2
        r = _min_circle_radius_three(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(r, radius1) == "GT":
            return True
    return False


def _lic10(x: List[float], y: List[float], n: int, c_pts: int, d_pts: int, epsilon: float) -> bool:
    if realcompare(float(n), 5.0) == "LT":
        return False
    span = c_pts + d_pts + 2
    for i in range(n - span + 1):
        j = i + c_pts + 1
        k = i + c_pts + d_pts + 2
        ang = _angle_at_vertex(x[i], y[i], x[j], y[j], x[k], y[k])
        if ang is None:
            continue
        if realcompare(ang, PI - epsilon) == "LT" or realcompare(ang, PI + epsilon) == "GT":
            return True
    return False


def _lic11(x: List[float], y: List[float], n: int, e_pts: int, f_pts: int, area1: float) -> bool:
    if realcompare(float(n), 5.0) == "LT":
        return False
    span = e_pts + f_pts + 2
    for i in range(n - span + 1):
        j = i + e_pts + 1
        k = i + e_pts + f_pts + 2
        t = _triangle_area_twice(x[i], y[i], x[j], y[j], x[k], y[k])
        area = abs(t) / 2.0
        if realcompare(area, area1) == "GT":
            return True
    return False


def _lic12(x: List[float], y: List[float], n: int, g_pts: int) -> bool:
    if realcompare(float(n), 3.0) == "LT":
        return False
    span = g_pts + 1
    for i in range(n - span):
        j = i + span
        if realcompare(x[j] - x[i], 0.0) == "LT":
            return True
    return False


def _lic13(x: List[float], y: List[float], n: int, k_pts: int, length1: float, length2: float) -> bool:
    if realcompare(float(n), 3.0) == "LT":
        return False
    span = k_pts + 1
    gt_len1 = False
    lt_len2 = False
    for i in range(n - span):
        j = i + span
        d = _dist(x, y, i, j)
        if realcompare(d, length1) == "GT":
            gt_len1 = True
        if realcompare(d, length2) == "LT":
            lt_len2 = True
        if gt_len1 and lt_len2:
            return True
    return False


def _lic14(
    x: List[float], y: List[float], n: int, a_pts: int, b_pts: int, radius1: float, radius2: float
) -> bool:
    if realcompare(float(n), 5.0) == "LT":
        return False
    span = a_pts + b_pts + 2
    part1 = False
    part2 = False
    for i in range(n - span + 1):
        j = i + a_pts + 1
        k = i + a_pts + b_pts + 2
        r = _min_circle_radius_three(x[i], y[i], x[j], y[j], x[k], y[k])
        if realcompare(r, radius1) == "GT":
            part1 = True
        if realcompare(r, radius2) != "GT":
            part2 = True
        if part1 and part2:
            return True
    return False


def _lic15(
    x: List[float], y: List[float], n: int, e_pts: int, f_pts: int, area1: float, area2: float
) -> bool:
    if realcompare(float(n), 5.0) == "LT":
        return False
    span = e_pts + f_pts + 2
    part1 = False
    part2 = False
    for i in range(n - span + 1):
        j = i + e_pts + 1
        k = i + e_pts + f_pts + 2
        t = _triangle_area_twice(x[i], y[i], x[j], y[j], x[k], y[k])
        area = abs(t) / 2.0
        if realcompare(area, area1) == "GT":
            part1 = True
        if realcompare(area, area2) == "LT":
            part2 = True
        if part1 and part2:
            return True
    return False


def decide(
    numpoints: int,
    x: List[float],
    y: List[float],
    parameters: Dict[str, Any],
    lcm: List[List[str]],
    pum_diag: List[bool],
) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    p = parameters
    length1 = float(p["LENGTH1"])
    radius1 = float(p["RADIUS1"])
    epsilon = float(p["EPSILON"])
    area1 = float(p["AREA1"])
    q_pts = int(p["Q_PTS"])
    quads = int(p["QUADS"])
    dist_p = float(p["DIST"])
    n_pts = int(p["N_PTS"])
    k_pts = int(p["K_PTS"])
    a_pts = int(p["A_PTS"])
    b_pts = int(p["B_PTS"])
    c_pts = int(p["C_PTS"])
    d_pts = int(p["D_PTS"])
    e_pts = int(p["E_PTS"])
    f_pts = int(p["F_PTS"])
    g_pts = int(p["G_PTS"])
    length2 = float(p["LENGTH2"])
    radius2 = float(p["RADIUS2"])
    area2 = float(p["AREA2"])

    n = numpoints
    cmv = [
        _lic1(x, y, n, length1),
        _lic2(x, y, n, radius1),
        _lic3(x, y, n, epsilon),
        _lic4(x, y, n, area1),
        _lic5(x, y, n, q_pts, quads),
        _lic6(x, y, n),
        _lic7(x, y, n, n_pts, dist_p),
        _lic8(x, y, n, k_pts, length1),
        _lic9(x, y, n, a_pts, b_pts, radius1),
        _lic10(x, y, n, c_pts, d_pts, epsilon),
        _lic11(x, y, n, e_pts, f_pts, area1),
        _lic12(x, y, n, g_pts),
        _lic13(x, y, n, k_pts, length1, length2),
        _lic14(x, y, n, a_pts, b_pts, radius1, radius2),
        _lic15(x, y, n, e_pts, f_pts, area1, area2),
    ]

    pum: List[List[bool]] = [[False] * 15 for _ in range(15)]
    for i in range(15):
        pum[i][i] = pum_diag[i]

    for i in range(15):
        for j in range(15):
            if i == j:
                continue
            conn = lcm[i][j]
            if conn == "NOTUSED":
                pum[i][j] = True
            elif conn == "ANDD":
                pum[i][j] = cmv[i] and cmv[j]
            elif conn == "ORR":
                pum[i][j] = cmv[i] or cmv[j]
            else:
                pum[i][j] = True

    fuv: List[bool] = []
    for i in range(15):
        row_all = True
        for j in range(15):
            if not pum[i][j]:
                row_all = False
                break
        fuv.append((not pum[i][i]) or row_all)

    launch = all(fuv)
    return (cmv, pum, fuv, launch)
